<style type="text/css">
:root {
  --primary-color: #1F6AA5;
  --secondary-color: #2E8B9E;
  --accent-color: #F39C12;
  --success-color: #27AE60;
  --danger-color: #E74C3C;
  --light-gray: #ECF0F1;
  --dark-gray: #34495E;
}

body {
  font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
  background-color: #F8F9FA;
  color: var(--dark-gray);
}

.hero-section {
  background: linear-gradient(135deg, var(--primary-color) 0%, var(--secondary-color) 100%);
  color: white;
  padding: 50px 30px;
  border-radius: 10px;
  margin-bottom: 40px;
  box-shadow: 0 4px 15px rgba(0,0,0,0.1);
}

.hero-section h1 {
  margin: 0 0 15px 0;
  font-size: 2.5em;
  font-weight: 700;
}

.hero-section p {
  margin: 0;
  font-size: 1.1em;
  opacity: 0.95;
  line-height: 1.6;
}

.form-section {
  background: white;
  padding: 40px;
  border-radius: 8px;
  box-shadow: 0 2px 8px rgba(0,0,0,0.08);
  margin-bottom: 40px;
}

.form-section h2 {
  color: var(--primary-color);
  border-bottom: 3px solid var(--accent-color);
  padding-bottom: 15px;
  margin-bottom: 30px;
  font-size: 1.8em;
}

.form-grid {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 20px;
  margin-bottom: 25px;
}

.form-group {
  display: flex;
  flex-direction: column;
}

.form-group label {
  font-weight: 600;
  color: var(--dark-gray);
  margin-bottom: 8px;
  font-size: 0.95em;
}

.form-group input,
.form-group select,
.form-group textarea {
  padding: 12px;
  border: 2px solid var(--light-gray);
  border-radius: 5px;
  font-size: 1em;
  font-family: inherit;
  transition: border-color 0.3s ease;
}

.form-group input:focus,
.form-group select:focus,
.form-group textarea:focus {
  outline: none;
  border-color: var(--primary-color);
  box-shadow: 0 0 5px rgba(31, 106, 165, 0.2);
}

.form-group.full {
  grid-column: 1 / -1;
}

.alert-info {
  background-color: #E3F2FD;
  border-left: 4px solid var(--primary-color);
  padding: 15px;
  border-radius: 4px;
  margin-bottom: 30px;
  color: #1565C0;
}

.table-section {
  background: white;
  padding: 40px;
  border-radius: 8px;
  box-shadow: 0 2px 8px rgba(0,0,0,0.08);
  margin-bottom: 40px;
}

.table-section h2 {
  color: var(--primary-color);
  border-bottom: 3px solid var(--accent-color);
  padding-bottom: 15px;
  margin-bottom: 30px;
  font-size: 1.8em;
}

.item-table-container {
  overflow-x: auto;
  margin: 20px 0;
}

.item-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 0.95em;
}

.item-table thead {
  background-color: var(--primary-color);
  color: white;
  position: sticky;
  top: 0;
}

.item-table thead th {
  padding: 15px;
  text-align: left;
  border: 1px solid #ddd;
  font-weight: 600;
}

.item-table tbody tr:nth-child(even) {
  background-color: #F8F9FA;
}

.item-table tbody tr:hover {
  background-color: #E8F4F8;
}

.item-table td {
  padding: 12px 15px;
  border: 1px solid #ddd;
}

.quality-rating, .clarity-rating {
  width: 60px;
  padding: 8px;
  border: 1px solid var(--light-gray);
  border-radius: 4px;
  font-size: 0.95em;
}

.comment-input {
  width: 100%;
  padding: 8px;
  border: 1px solid var(--light-gray);
  border-radius: 4px;
  font-size: 0.9em;
  font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
  resize: vertical;
  min-width: 150px;
}

.button-group {
  display: flex;
  gap: 15px;
  margin-top: 40px;
  justify-content: center;
  flex-wrap: wrap;
}

.btn {
  padding: 14px 35px;
  border: none;
  border-radius: 5px;
  font-size: 1em;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.3s ease;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.btn-primary {
  background-color: var(--primary-color);
  color: white;
  box-shadow: 0 4px 10px rgba(31, 106, 165, 0.3);
}

.btn-primary:hover {
  background-color: #165080;
  transform: translateY(-2px);
  box-shadow: 0 6px 15px rgba(31, 106, 165, 0.4);
}

.btn-secondary {
  background-color: var(--light-gray);
  color: var(--dark-gray);
  box-shadow: 0 2px 5px rgba(0,0,0,0.1);
}

.btn-secondary:hover {
  background-color: #D5DBDB;
  transform: translateY(-2px);
}

.success-message {
  background-color: #D5F4E6;
  border-left: 4px solid var(--success-color);
  padding: 15px;
  border-radius: 4px;
  color: #186A3B;
  margin-bottom: 20px;
  display: none;
  animation: slideIn 0.3s ease;
}

.error-message {
  background-color: #FADBD8;
  border-left: 4px solid var(--danger-color);
  padding: 15px;
  border-radius: 4px;
  color: #A93226;
  margin-bottom: 20px;
  display: none;
  animation: slideIn 0.3s ease;
}

@keyframes slideIn {
  from {
    opacity: 0;
    transform: translateY(-10px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.loading {
  display: none;
  text-align: center;
  padding: 20px;
}

.spinner {
  border: 4px solid var(--light-gray);
  border-top: 4px solid var(--primary-color);
  border-radius: 50%;
  width: 40px;
  height: 40px;
  animation: spin 1s linear infinite;
  margin: 0 auto;
}

@keyframes spin {
  0% { transform: rotate(0deg); }
  100% { transform: rotate(360deg); }
}
</style>
:::


